validate(data: Record<string, unknown>): ValidationResult[] {
  const errors: ValidationResult[] = [];

  for (const [field, rules] of this.rules) {
    const value = this.getNestedValue(data, field);

    for (const rule of rules) {
      if (rule.type === 'required' && (value === undefined || value === null || value === '')) {
        errors.push({ field, message: rule.message || `${field} is required` });
      }
      if (rule.type === 'minLength' && typeof value === 'string' && value.length < rule.min!) {
        errors.push({ field, message: rule.message || `${field} must be at least ${rule.min} characters` });
      }
      if (rule.type === 'maxLength' && typeof value === 'string' && value.length > rule.max!) {
        errors.push({ field, message: rule.message || `${field} must be at most ${rule.max} characters` });
      }
      if (rule.type === 'pattern' && typeof value === 'string' && rule.pattern && !rule.pattern.test(value)) {
        errors.push({ field, message: rule.message || `${field} has invalid format` });
      }
      if (rule.type === 'custom' && rule.validator && !rule.validator(value)) {
        errors.push({ field, message: rule.message || `${field} validation failed` });
      }
    }
  }

  return errors;
}

private getNestedValue(data: Record<string, unknown>, path: string): unknown {
  const parts = path.split('.');
  let current: unknown = data;
  for (const part of parts) {
    if (current === null || current === undefined) return undefined;
    current = (current as Record<string, unknown>)[part];
  }
  return current;
}
